import{_ as i,o as a,c as s,ak as t}from"./chunks/framework.D-xjpKOc.js";const m=JSON.parse('{"title":"Guide de Workflow Git","description":"","frontmatter":{},"headers":[],"relativePath":"fr/devdoc/git_workflow.md","filePath":"fr/devdoc/git_workflow.md"}'),o={name:"fr/devdoc/git_workflow.md"};function l(r,e,n,c,d,h){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="guide-de-workflow-git" tabindex="-1">Guide de Workflow Git <a class="header-anchor" href="#guide-de-workflow-git" aria-label="Permalink to “Guide de Workflow Git”">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>Ce guide centralise les règles de contribution pour les développeurs travaillant sur le projet. Il combine la nomenclature des branches, les conventions de commit et la configuration des Git hooks en un seul endroit.</p><h2 id="_1-nomenclature-des-branches" tabindex="-1">1. Nomenclature des branches <a class="header-anchor" href="#_1-nomenclature-des-branches" aria-label="Permalink to “1. Nomenclature des branches”">​</a></h2><p>Nous utilisons une stratégie de branchement conventionnelle pour garder le dépôt propre et facile à naviguer.</p><p>Utilisez l&#39;un de ces préfixes :</p><ul><li><code>main/</code> : branche production stable</li><li><code>dev/</code> : intégration et développement en cours</li><li><code>feat/</code> : nouvelle fonctionnalité ou amélioration</li><li><code>fix/</code> : correction de bug</li><li><code>hotfix/</code> : correction urgente de production</li><li><code>chore/</code> : tâches de maintenance (dépendances, docs, outils)</li></ul><p>Exemples de noms de branches :</p><ul><li><code>feat/post-processing-bloom</code></li><li><code>fix/framebuffer-resize-crash</code></li><li><code>chore/update-docs-links</code></li></ul><p>Référence : <a href="https://conventional-branch.github.io" target="_blank" rel="noreferrer">Conventional Branch</a></p><h2 id="_2-messages-de-commit" tabindex="-1">2. Messages de commit <a class="header-anchor" href="#_2-messages-de-commit" aria-label="Permalink to “2. Messages de commit”">​</a></h2><p>Suivez le format Conventional Commits :</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;type&gt;(scope optionnel): &lt;description&gt;</span></span></code></pre></div><p>Types de commit courants :</p><ul><li><code>feat</code> : nouvelle fonctionnalité</li><li><code>fix</code> : correction de bug</li><li><code>build</code> : système de build ou dépendances</li><li><code>chore</code> : travaux de maintenance</li><li><code>ci</code> : modifications CI/CD</li><li><code>docs</code> : mises à jour de documentation</li><li><code>style</code> : changements de formatage/style uniquement</li><li><code>refactor</code> : refactorisation sans changement de comportement</li><li><code>perf</code> : amélioration de performance</li><li><code>test</code> : tests ajoutés ou mis à jour</li></ul><p>Exemples :</p><ul><li><code>feat(renderer): add chromatic aberration effect</code></li><li><code>fix(opengl): prevent invalid framebuffer bind</code></li><li><code>docs(devdoc): merge quality contribution guidelines</code></li></ul><p>Référence : <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a></p><h2 id="_3-git-hooks-avec-pre-commit" tabindex="-1">3. Git Hooks avec pre-commit <a class="header-anchor" href="#_3-git-hooks-avec-pre-commit" aria-label="Permalink to “3. Git Hooks avec pre-commit”">​</a></h2><p>Les Git hooks natifs sont locaux et non versionnés. Nous utilisons <strong>pre-commit</strong> afin que tout le monde exécute les mêmes vérifications.</p><h3 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to “Prérequis”">​</a></h3><ul><li>Python 3.6+</li><li>pip</li><li>Git</li></ul><h3 id="installer-pre-commit" tabindex="-1">Installer pre-commit <a class="header-anchor" href="#installer-pre-commit" aria-label="Permalink to “Installer pre-commit”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pre-commit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pre-commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><h3 id="activer-les-hooks" tabindex="-1">Activer les hooks <a class="header-anchor" href="#activer-les-hooks" aria-label="Permalink to “Activer les hooks”">​</a></h3><p>À partir de la racine du dépôt :</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pre-commit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h3 id="executer-toutes-les-verifications-une-fois" tabindex="-1">Exécuter toutes les vérifications une fois <a class="header-anchor" href="#executer-toutes-les-verifications-une-fois" aria-label="Permalink to “Exécuter toutes les vérifications une fois”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pre-commit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all-files</span></span></code></pre></div><h3 id="ignorer-les-hooks-temporairement-non-recommande" tabindex="-1">Ignorer les hooks temporairement (non recommandé) <a class="header-anchor" href="#ignorer-les-hooks-temporairement-non-recommande" aria-label="Permalink to “Ignorer les hooks temporairement (non recommandé)”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-verify</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Votre message de commit&quot;</span></span></code></pre></div><p>Référence : <a href="https://pre-commit.com/" target="_blank" rel="noreferrer">pre-commit</a></p><h2 id="_4-workflow-de-contribution-recommande" tabindex="-1">4. Workflow de contribution recommandé <a class="header-anchor" href="#_4-workflow-de-contribution-recommande" aria-label="Permalink to “4. Workflow de contribution recommandé”">​</a></h2><ol><li>Créez une branche avec le préfixe approprié.</li><li>Implémentez votre changement.</li><li>Exécutez les hooks et les tests localement.</li><li>Écrivez des messages Conventional Commit clairs.</li><li>Ouvrez votre pull request en ciblant la branche attendue.</li></ol><p>Garder ce workflow cohérent aide les révisions à avancer plus rapidement et garde l&#39;historique du projet lisible.</p>`,35)])])}const k=i(o,[["render",l]]);export{m as __pageData,k as default};
